def gen(rng, size):
    n = size
    edges = set()
    for _ in range(size):
        a = rng.randint(0, n - 1)
        b = rng.randint(0, n - 1)
        if a != b:
            edge = (min(a,b), max(a,b))
            edges.add(edge)
    return [n, list(list(e) for e in edges)]

