class Solution:
    def makeConnected(self, n: int, connections) -> int:
        if len(connections) < n - 1:
            return -1
        visited = [False] * n
        adj = [[] for _ in range(n)]
        for a, b in connections:
            adj[a].append(b)
            adj[b].append(a)
        components = 0
        for start in range(n):
            if not visited[start]:
                components += 1
                stack = [start]
                while stack:
                    node = stack.pop()
                    if visited[node]:
                        continue
                    visited[node] = True
                    for nb in adj[node]:
                        if not visited[nb]:
                            stack.append(nb)
        return components - 1

